VALUES
  ('promotion-53250add-moex-00138', 'promotion-53250add', 'promotion-53250add-moex-110-9b7ab1bb', 'sub-promotion-53250add-03', NULL, 'single_choice', '甲有一宗 A 地，為雙重買賣；先與乙訂立買賣契約，將 A 地交付予乙；嗣後又與丙訂立買賣契 約，將A地所有權移轉登記給丙。何人取得A地之所有權？', '["乙", "丙", "乙與丙分別共有", "乙與丙公同共有 13740、40140 41140"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:46+00:00", "source_pdf_sha1": "f79d180b0fb7", "answer_pdf_sha1": "925f95dadfe6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "137", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('promotion-53250add-moex-00139', 'promotion-53250add', 'promotion-53250add-moex-110-9b7ab1bb', 'sub-promotion-53250add-03', NULL, 'single_choice', '依民法規定，下列關於出租人及承租人權利義務及責任之敘述，何者錯誤？', '["耕作地之出租人不得預收租金", "就租賃物應納之一切稅捐，由承租人負擔", "租賃物為動物者，其飼養費由承租人負擔", "租賃物之修繕，除契約另有訂定或另有習慣外，由出租人負擔"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:46+00:00", "source_pdf_sha1": "f79d180b0fb7", "answer_pdf_sha1": "925f95dadfe6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "137", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('promotion-53250add-moex-00140', 'promotion-53250add', 'promotion-53250add-moex-110-9b7ab1bb', 'sub-promotion-53250add-03', NULL, 'single_choice', '試驗買賣，為以買受人之承認標的物為停止條件而訂立之契約。下列何種情形，不得視為承認？', '["買受人不經試驗，即拒絕承認", "標的物因試驗已交付於買受人，而買受人不交還其物", "於約定期限，買受人不為拒絕之表示", "出賣人所定之相當期限內，買受人不為拒絕之表示"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:46+00:00", "source_pdf_sha1": "f79d180b0fb7", "answer_pdf_sha1": "925f95dadfe6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "137", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('promotion-53250add-moex-00141', 'promotion-53250add', 'promotion-53250add-moex-110-9b7ab1bb', 'sub-promotion-53250add-03', NULL, 'single_choice', '甲贈與Ａ畫給乙，乙允受之。下列敘述，何者正確？', '["贈與物之權利移轉前，或移轉後，甲皆得任意撤銷其贈與", "經公證之贈與，縱使受贈人乙對贈與人甲有故意傷害行為，仍不得撤銷", "乙因故意傷害行為導致贈與人甲死亡，甲之繼承人得於知有撤銷原因之時起，6個月內撤銷贈與", "贈與人於贈與約定後，經濟情況顯有變更，致影響生計時，得撤銷贈與"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:46+00:00", "source_pdf_sha1": "f79d180b0fb7", "answer_pdf_sha1": "925f95dadfe6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "137", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('promotion-53250add-moex-00142', 'promotion-53250add', 'promotion-53250add-moex-110-9b7ab1bb', 'sub-promotion-53250add-03', NULL, 'single_choice', '甲乙丙三兄弟，因繼承父親之遺產而公同共有A地；甲未經乙丙同意，擅自與丁訂立買賣契約， 將A地賣給丁。下列敘述，何者正確？', '["甲與丁訂立之A地買賣契約有效", "甲丁買賣契約因自始不能，故無效", "甲丁買賣契約經乙丙同意，始有效", "乙丙得撤銷甲丁訂立之買賣契約"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:46+00:00", "source_pdf_sha1": "f79d180b0fb7", "answer_pdf_sha1": "925f95dadfe6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "137", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('promotion-53250add-moex-00143', 'promotion-53250add', 'promotion-53250add-moex-110-9b7ab1bb', 'sub-promotion-53250add-03', NULL, 'single_choice', '甲公司是乙公司之經銷商，向乙公司進貨，銷售乙公司之產品；由甲提供A地為乙設定最高限額 新臺幣 1,000 萬元之最高限額抵押權，用以擔保乙對甲因經銷關係所生之債權。下列債權，何者 並非最高限額抵押權所擔保之債權？', '["因甲債務不履行，而乙因此取得對甲之損害賠償債權", "甲因財務困難向乙貸款，乙因此取得對甲之借款返還債權", "甲要求乙將貨物送達清償地以外之處所，乙因此取得對甲之運費債權", "甲為支付貨款簽發票據，乙因此取得之票款債權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:46+00:00", "source_pdf_sha1": "f79d180b0fb7", "answer_pdf_sha1": "925f95dadfe6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "137", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('promotion-53250add-moex-00144', 'promotion-53250add', 'promotion-53250add-moex-110-9b7ab1bb', 'sub-promotion-53250add-03', NULL, 'single_choice', '下列何者契約，縱經登記，亦不生對抗第三人之物權化效力？', '["共有物之分管契約", "共有物之不分割契約", "房屋租賃契約", "流押（流抵）契約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:46+00:00", "source_pdf_sha1": "f79d180b0fb7", "answer_pdf_sha1": "925f95dadfe6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "137", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('promotion-53250add-moex-00145', 'promotion-53250add', 'promotion-53250add-moex-110-9b7ab1bb', 'sub-promotion-53250add-03', NULL, 'single_choice', '以有價證券為質權之標的物者，其附屬於該證券之利息證券、定期金證券或其他附屬證券，依民 法規定，下列何者為質權效力所及？', '["設質前已發行之附屬證券，以已交付於質權人者為限，為質權效力所及", "設質前已發行之附屬證券，無論是否已交付於質權人者，均為質權效力所及", "設質後所發行之附屬證券，以已交付於質權人者為限，為質權效力所及", "設質前後所發行之附屬證券，基於證券交易之原理，無論是否已交付於質權人者，均為質權效 力所及"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:46+00:00", "source_pdf_sha1": "f79d180b0fb7", "answer_pdf_sha1": "925f95dadfe6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "137", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('promotion-53250add-moex-00146', 'promotion-53250add', 'promotion-53250add-moex-110-9b7ab1bb', 'sub-promotion-53250add-03', NULL, 'single_choice', '甲登記為A地所有人，在A地上設定20年期限之普通地上權於乙。甲與乙約定，乙每年應支付 新臺幣15萬元地租於甲。下列敘述，何者正確？', '["乙得逕行占有A地", "乙得在A地上下為建築物及其他工作物目的外之使用", "乙得讓與A地之地上權於他人", "乙得隨時拋棄其於A地之地上權 13740、40140 41140"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:46+00:00", "source_pdf_sha1": "f79d180b0fb7", "answer_pdf_sha1": "925f95dadfe6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "137", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('promotion-53250add-moex-00147', 'promotion-53250add', 'promotion-53250add-moex-110-9b7ab1bb', 'sub-promotion-53250add-03', NULL, 'single_choice', '甲為A公司董事長。A公司為B車所有人，以B車為甲之專用座車。A公司僱用乙為司機兼保 鑣，專以B車接送並保護甲，並將B車交付於乙保管。某日，乙以B車接送甲至某公司開會，A 公司所僱用之董事長特助丙，亦在隨行之列。下列敘述，何者正確？', '["甲為B車之占有人", "乙為B車之占有人", "A公司為B車之占有人", "丙為B車之占有人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:46+00:00", "source_pdf_sha1": "f79d180b0fb7", "answer_pdf_sha1": "925f95dadfe6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "137", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "智慧財產行政"}'::jsonb, NULL)
